package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.IOException;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.assertEquals;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

public class CSVFormatTest {

    @Test
    public void testGetAllowMissingColumnNames() throws Exception {
        // Given
        CSVFormat csvFormat = new CSVFormat(',', '\"', null, null, null,
                false, true, "\r\n", null, null, false, true);

        // When
        boolean result = csvFormat.getAllowMissingColumnNames();

        // Then
        assertEquals(true, result);
    }

    @Test
    public void testGetAllowMissingColumnNamesFalse() throws Exception {
        // Given
        CSVFormat csvFormat = new CSVFormat(',', '\"', null, null, null,
                false, true, "\r\n", null, null, false, false);

        // When
        boolean result = csvFormat.getAllowMissingColumnNames();

        // Then
        assertEquals(false, result);
    }

    @Test
    public void testGetAllowMissingColumnNamesUsingReflection() throws Exception {
        // Given
        CSVFormat csvFormat = new CSVFormat(',', '\"', null, null, null,
                false, true, "\r\n", null, null, false, true);

        // When
        boolean result;
        try {
            java.lang.reflect.Method method = CSVFormat.class.getDeclaredMethod("getAllowMissingColumnNames");
            method.setAccessible(true);
            result = (boolean) method.invoke(csvFormat);
        } catch (NoSuchMethodException e) {
            result = false;
        }

        // Then
        assertEquals(true, result);
    }
}
